"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[4878],{6277(e){e.exports=JSON.parse('{"tag":{"label":"cloud","permalink":"/tags/cloud","allTagsPath":"/tags","count":24,"items":[{"id":"development/data-handling/compress-stored-data","title":"Compress stored data","description":"Storing uncompressed data wastes bandwidth and increases storage capacity requirements; applying appropriate compression reduces both storage consumption and the energy needed to read and write it.","permalink":"/development/data-handling/compress-stored-data"},{"id":"architecture/system-topology/containerize-your-workload-where-applicable","title":"Containerize your workloads","description":"Containerizing workloads enables better resource utilisation and bin packing, reducing unnecessary compute allocation and embodied carbon compared to running full virtual machines.","permalink":"/architecture/system-topology/containerize-your-workload-where-applicable"},{"id":"requirements/encrypt-what-is-necessary","title":"Encrypt what is necessary","description":"Data protection through encryption is a crucial aspect of our security measures. However, the encryption process can be resource-intensive at multiple levels.","permalink":"/requirements/encrypt-what-is-necessary"},{"id":"architecture/technology-selection/evaluate-other-cpu-architectures","title":"Evaluate other CPU architectures","description":"Applications are built with a software architecture that best fits the business need they are serving. Cloud providers make it easy to evaluate other CPU types","permalink":"/architecture/technology-selection/evaluate-other-cpu-architectures"},{"id":"architecture/system-topology/implement-stateless-design","title":"Implement stateless design","description":"Service state refers to the in-memory or on-disk data required by a service to function. State includes the data structures and member variables that the service reads and writes. Depending on how the service is architected, the state might also include files or other resources stored on the disk. Applications that consume large memory or on-disk data require larger VM sizes, especially for cloud computing where you would need larger VM SKUs to support high RAM capacity and multiple data disks.","permalink":"/architecture/system-topology/implement-stateless-design"},{"id":"requirements/match-slo","title":"Match your service level objectives to business needs","description":"If service downtimes are acceptable it\'s better to not strive for highest availability but to design the solution according to real business needs. Lower availability guarantees can help reduce energy consumption by using less infrastructure components.","permalink":"/requirements/match-slo"},{"id":"development/minimizing-deployed-environments","title":"Minimize the total number of deployed environments","description":"In a given application, there may be a need to utilize multiple environments in the application workflow. Typically, a development environment is used for regular updates, while staging or testing enviroments are used to make sure there are no issues before code reaches a production environment where users may have access. Each added environment has an increasing energy impact, which in turn creates more emissions. As such, it is important to understand the necessity of each enviroment and it\'s environmental impact.","permalink":"/development/minimizing-deployed-environments"},{"id":"requirements/optimize-impact-on-customer-equipment","title":"Optimize impact on customer devices and equipment","description":"Software that demands frequent hardware upgrades increases embodied carbon from device manufacturing; designing for backwards compatibility extends device lifetimes and reduces the carbon footprint of customer equipment.","permalink":"/requirements/optimize-impact-on-customer-equipment"},{"id":"architecture/system-topology/queue-non-urgent-requests","title":"Queue non-urgent processing requests","description":"All systems have periods of peak and low load. From a hardware-efficiency perspective, we are more efficient with hardware if we minimise the impact of request spikes with an implementation that allows an even utilization of components. From an energy-efficiency perspective, we are more efficient with energy if we ensure that idle resources are kept to a minimum.","permalink":"/architecture/system-topology/queue-non-urgent-requests"},{"id":"architecture/system-topology/reduce-network-traversal-between-VMs","title":"Reduce network traversal between VMs","description":"Placing VMs in the same region or availability zone minimises the physical distance data must travel between instances, reducing the energy consumed by network traversal.","permalink":"/architecture/system-topology/reduce-network-traversal-between-VMs"},{"id":"operations/resource-lifecycle/remove-unused-assets","title":"Remove unused assets","description":"Unused cloud resources such as databases, storage buckets, and compute instances continue to consume energy and generate embodied carbon; identifying and decommissioning them eliminates unnecessary waste.","permalink":"/operations/resource-lifecycle/remove-unused-assets"},{"id":"operations/capacity-management/scale-down-unused-applications","title":"Scale down applications when not in use","description":"Applications consume CPU even when they are not actively in use. For example, background timers, garbage collection, health checks, etc. Even when the application is shut down, the underlying hardware is consuming idle power.","permalink":"/operations/capacity-management/scale-down-unused-applications"},{"id":"operations/capacity-management/scale-infrastructure-with-user-load","title":"Scale infrastructure with user load","description":"Demand for resources depends on user load at any given time. However, most applications run without taking this into consideration. As a result,resources are underused and inefficient.","permalink":"/operations/capacity-management/scale-infrastructure-with-user-load"},{"id":"operations/capacity-management/scale-kubernetes-workloads-based-on-events","title":"Scale Kubernetes workloads based on relevant demand metrics","description":"By default, Kubernetes scales workloads based on CPU and RAM utilization. In practice, however, it\'s difficult to correlate your application\'s demand drivers with CPU and RAM utilization. Scaling your workload based on relevant demand metrics that drive scaling of your applications, such as HTTP requests, queue length, and cloud alerting events can help reduce resource utilization, and therefore also your carbon emissions.","permalink":"/operations/capacity-management/scale-kubernetes-workloads-based-on-events"},{"id":"architecture/system-topology/scale-logical-components-independently","title":"Scale logical components independently","description":"Decomposing applications into independently scalable microservices allows each component to be right-sized for its own demand, reducing overall compute resource consumption and embodied carbon.","permalink":"/architecture/system-topology/scale-logical-components-independently"},{"id":"operations/scan-for-vulnerabilities","title":"Scan for vulnerabilities","description":"Many attacks on cloud infrastructure seek to misuse deployed resources, which leads to an unnecessary spike in usage and cost.","permalink":"/operations/scan-for-vulnerabilities"},{"id":"development/evaluate-whether-to-use-TLS-termination","title":"Terminate TLS at border gateway","description":"Transport Layer Security (TLS) ensures that all data passed between the web server and web browsers remain private and encrypted. However, terminating and re-establishing TLS increases CPU usage and might be unnecessary in certain architectures.","permalink":"/development/evaluate-whether-to-use-TLS-termination"},{"id":"architecture/system-topology/evaluate-using-a-service-mesh","title":"Use a service mesh only if needed","description":"Service meshes add overhead through additional containers and increased network traffic, so they should only be deployed for applications that genuinely require the capabilities they provide.","permalink":"/architecture/system-topology/evaluate-using-a-service-mesh"},{"id":"development/use-async-instead-of-sync","title":"Use Asynchronous network calls instead of synchronous","description":"When making calls across process boundaries to either databases or file systems or REST APIs, relying on synchronous calls can cause the calling thread to become blocked, putting additional load on the CPU","permalink":"/development/use-async-instead-of-sync"},{"id":"operations/use-cloud-native-network-security-tools-and-controls","title":"Use cloud native network security tools and controls","description":"Network and web application firewalls provide protection against most common attacks and load shedding bad bots. These tools help to remove unnecessary data transmission and reduce the burden on the cloud infrastructure, while also using lower bandwidth and less infrastructure.","permalink":"/operations/use-cloud-native-network-security-tools-and-controls"},{"id":"architecture/technology-selection/use-energy-efficient-hardware","title":"Use cloud native processor VMs","description":"Cloud VMs built on energy-efficient processors, such as ARM-based cloud-native chips, can run scale-out workloads with significantly lower energy consumption and embodied carbon than traditional alternatives.","permalink":"/architecture/technology-selection/use-energy-efficient-hardware"},{"id":"development/media-and-code-efficiency/use-compiled-languages","title":"Use compiled languages","description":"Interpreted languages re-parse and compile code on every execution, consuming more energy than pre-compiled binaries, which perform compilation once and run more efficiently at runtime.","permalink":"/development/media-and-code-efficiency/use-compiled-languages"},{"id":"operations/use-ddos-protection","title":"Use DDoS protection","description":"Distributed denial of service (DDoS) attacks are used to increase the server load so that it is unable to respond to any legitimate requests. This is usually done to harm the owner of the service or hardware.","permalink":"/operations/use-ddos-protection"},{"id":"architecture/technology-selection/use-serverless","title":"Use serverless cloud services","description":"Serverless cloud services scale dynamically with demand and share infrastructure across many applications, reducing idle resource consumption and lowering embodied carbon emissions.","permalink":"/architecture/technology-selection/use-serverless"}],"unlisted":false}}')}}]);